/**
 * @file fft_radix3_avx512_ct_n1_scaled.h
 * @brief DFT-3 AVX512 n1_scaled (separate is/os, output *= scale)
 *
 * FFTW-style codelet for recursive CT executor.
 * Generated by gen_radix3.py --variant ct_n1_scaled
 */

#ifndef FFT_RADIX3_AVX512_CT_CT_N1_SCALED_H
#define FFT_RADIX3_AVX512_CT_CT_N1_SCALED_H

#include <immintrin.h>

#ifndef R3L_CT_LD
#define R3L_CT_LD(p) _mm512_loadu_pd(p)
#define R3L_CT_ST(p,v) _mm512_storeu_pd((p),(v))
#endif
#define LD R3L_CT_LD
#define ST R3L_CT_ST

static __attribute__((target("avx512f,avx512dq,fma"))) void
radix3_n1_scaled_fwd_avx512(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    size_t is, size_t os, size_t vl, double scale)
{
    const __m512d sign_flip = _mm512_set1_pd(-0.0);
    const __m512d KHALF = _mm512_set1_pd(0.500000000000000000000000000000000000000000000);
    const __m512d KS    = _mm512_set1_pd(0.866025403784438596588302061718422919511795044);
    (void)sign_flip;  /* unused by current butterfly, reserved for neg() */

    __m512d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im;

    const __m512d vscale = _mm512_set1_pd(scale);

    for (size_t k = 0; k < vl; k += 8) {
        x0_re = LD(&in_re[0*is+k]);
        x0_im = LD(&in_im[0*is+k]);
        x1_re = LD(&in_re[1*is+k]);
        x1_im = LD(&in_im[1*is+k]);
        x2_re = LD(&in_re[2*is+k]);
        x2_im = LD(&in_im[2*is+k]);

        /* DFT-3 butterfly [fwd] */
        __m512d ar=_mm512_add_pd(x1_re,x2_re), ai=_mm512_add_pd(x1_im,x2_im);
        __m512d dr=_mm512_sub_pd(x1_re,x2_re), di=_mm512_sub_pd(x1_im,x2_im);
        __m512d R1r=_mm512_fnmadd_pd(KHALF,ar,x0_re), R1i=_mm512_fnmadd_pd(KHALF,ai,x0_im);
        x0_re=_mm512_add_pd(x0_re,ar); x0_im=_mm512_add_pd(x0_im,ai);
        x1_re=_mm512_fmadd_pd(KS,di,R1r); x1_im=_mm512_fnmadd_pd(KS,dr,R1i);
        x2_re=_mm512_fnmadd_pd(KS,di,R1r); x2_im=_mm512_fmadd_pd(KS,dr,R1i);

        ST(&out_re[0*os+k], _mm512_mul_pd(vscale, x0_re));
        ST(&out_im[0*os+k], _mm512_mul_pd(vscale, x0_im));
        ST(&out_re[1*os+k], _mm512_mul_pd(vscale, x1_re));
        ST(&out_im[1*os+k], _mm512_mul_pd(vscale, x1_im));
        ST(&out_re[2*os+k], _mm512_mul_pd(vscale, x2_re));
        ST(&out_im[2*os+k], _mm512_mul_pd(vscale, x2_im));
    }
}

static __attribute__((target("avx512f,avx512dq,fma"))) void
radix3_n1_scaled_bwd_avx512(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    size_t is, size_t os, size_t vl, double scale)
{
    const __m512d sign_flip = _mm512_set1_pd(-0.0);
    const __m512d KHALF = _mm512_set1_pd(0.500000000000000000000000000000000000000000000);
    const __m512d KS    = _mm512_set1_pd(0.866025403784438596588302061718422919511795044);
    (void)sign_flip;  /* unused by current butterfly, reserved for neg() */

    __m512d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im;

    const __m512d vscale = _mm512_set1_pd(scale);

    for (size_t k = 0; k < vl; k += 8) {
        x0_re = LD(&in_re[0*is+k]);
        x0_im = LD(&in_im[0*is+k]);
        x1_re = LD(&in_re[1*is+k]);
        x1_im = LD(&in_im[1*is+k]);
        x2_re = LD(&in_re[2*is+k]);
        x2_im = LD(&in_im[2*is+k]);

        /* DFT-3 butterfly [bwd] */
        __m512d ar=_mm512_add_pd(x1_re,x2_re), ai=_mm512_add_pd(x1_im,x2_im);
        __m512d dr=_mm512_sub_pd(x1_re,x2_re), di=_mm512_sub_pd(x1_im,x2_im);
        __m512d R1r=_mm512_fnmadd_pd(KHALF,ar,x0_re), R1i=_mm512_fnmadd_pd(KHALF,ai,x0_im);
        x0_re=_mm512_add_pd(x0_re,ar); x0_im=_mm512_add_pd(x0_im,ai);
        x2_re=_mm512_fmadd_pd(KS,di,R1r); x2_im=_mm512_fnmadd_pd(KS,dr,R1i);
        x1_re=_mm512_fnmadd_pd(KS,di,R1r); x1_im=_mm512_fmadd_pd(KS,dr,R1i);

        ST(&out_re[0*os+k], _mm512_mul_pd(vscale, x0_re));
        ST(&out_im[0*os+k], _mm512_mul_pd(vscale, x0_im));
        ST(&out_re[1*os+k], _mm512_mul_pd(vscale, x1_re));
        ST(&out_im[1*os+k], _mm512_mul_pd(vscale, x1_im));
        ST(&out_re[2*os+k], _mm512_mul_pd(vscale, x2_re));
        ST(&out_im[2*os+k], _mm512_mul_pd(vscale, x2_im));
    }
}


#undef LD
#undef ST

#endif /* FFT_RADIX3_AVX512_CT_CT_N1_SCALED_H */
